import pygame
import random

# Initialize Pygame
pygame.init()

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
CELL_SIZE = 30
SCREEN_WIDTH = GRID_WIDTH * CELL_SIZE
SCREEN_HEIGHT = GRID_HEIGHT * CELL_SIZE
WHITE = (255, 255, 255)
BLACK = (0, 0, 0)
FPS = 30

# Set up the screen
screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
pygame.display.set_caption("Tetris Bejeweled")
clock = pygame.time.Clock()

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[None for _ in range(width)] for _ in range(height)]

    def is_valid_move(self, shape, x, y):
        for dx, dy in shape.get_current_shape():
            gx, gy = x + dx, y + dy
            if gx < 0 or gx >= self.width or gy < 0 or gy >= self.height:
                return False
            if gy >= 0 and self.grid[gy][gx] is not None:
                return False
        return True

    def lock_shape(self, shape):
        """Convert the tetromino blocks into gems in the grid."""
        for gx, gy in shape.get_coordinates():
            if 0 <= gx < self.width and 0 <= gy < self.height:
                self.grid[gy][gx] = shape.color

    def clear_full_rows(self):
        """Clear any full rows (Tetris) and return count of cleared rows."""
        cleared = 0
        new_grid = []
        for row in self.grid:
            if all(cell is not None for cell in row):
                cleared += 1
            else:
                new_grid.append(row)
        # Add empty rows at top
        for _ in range(cleared):
            new_grid.insert(0, [None]*self.width)
        self.grid = new_grid
        return cleared

    def find_matches(self):
        """Return set of (x,y) cells that form match-3+ horizontally or vertically."""
        matches = set()
        # Horizontal
        for y in range(self.height):
            x = 0
            while x < self.width:
                color = self.grid[y][x]
                if color is None:
                    x += 1
                    continue
                length = 1
                while x+length < self.width and self.grid[y][x+length] == color:
                    length += 1
                if length >= 3:
                    for i in range(length):
                        matches.add((x+i, y))
                x += length
        # Vertical
        for x in range(self.width):
            y = 0
            while y < self.height:
                color = self.grid[y][x]
                if color is None:
                    y += 1
                    continue
                length = 1
                while y+length < self.height and self.grid[y+length][x] == color:
                    length += 1
                if length >= 3:
                    for i in range(length):
                        matches.add((x, y+i))
                y += length
        return matches

    def clear_matches(self):
        """Clear all match-3+ gems, return number of cleared gems."""
        matches = self.find_matches()
        for x, y in matches:
            self.grid[y][x] = None
        return len(matches)

    def apply_gravity(self):
        """Drop gems down into empty spaces."""
        for x in range(self.width):
            write_row = self.height - 1
            for y in range(self.height-1, -1, -1):
                if self.grid[y][x] is not None:
                    self.grid[write_row][x] = self.grid[y][x]
                    if write_row != y:
                        self.grid[y][x] = None
                    write_row -= 1

    def draw(self, screen):
        for y in range(self.height):
            for x in range(self.width):
                if self.grid[y][x]:
                    pygame.draw.rect(screen, self.grid[y][x], (x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(screen, BLACK, (x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)  # Grid lines


class Tetromino:
    TETROMINO_COLORS = {
        'I': (0,255,255), 'J': (0,0,255), 'L': (255,165,0),
        'O': (255,255,0), 'S': (0,255,0), 'T': (128,0,128), 'Z': (255,0,0)
    }
    TETROMINO_SHAPES = {
        'I': [[(0,0),(1,0),(2,0),(3,0)], [(1,-1),(1,0),(1,1),(1,2)]],
        'J': [[(0,0),(0,1),(1,1),(2,1)], [(1,0),(2,0),(1,1),(1,2)],
              [(0,1),(1,1),(2,1),(2,2)], [(1,0),(1,1),(0,2),(1,2)]],
        'L': [[(2,0),(0,1),(1,1),(2,1)], [(1,0),(1,1),(1,2),(2,2)],
              [(0,1),(1,1),(2,1),(0,2)], [(0,0),(1,0),(1,1),(1,2)]],
        'O': [[(0,0),(1,0),(0,1),(1,1)]],
        'S': [[(1,0),(2,0),(0,1),(1,1)], [(0,0),(0,1),(1,1),(1,2)]],
        'T': [[(0,0),(1,0),(2,0),(1,1)], [(1,0),(0,1),(1,1),(1,2)],
              [(1,0),(0,1),(1,1),(2,1)], [(1,0),(1,1),(2,1),(1,2)]],
        'Z': [[(0,0),(1,0),(1,1),(2,1)], [(1,0),(0,1),(1,1),(0,2)]]
    }

    def __init__(self, x, y, tet_type=None):
        if tet_type in self.TETROMINO_SHAPES:
            self.type = tet_type
        else:
            self.type = random.choice(list(self.TETROMINO_SHAPES))
        self.orientations = self.TETROMINO_SHAPES[self.type]
        self.color = self.TETROMINO_COLORS[self.type]
        self.rotation = 0
        self.x = x
        self.y = y

    def get_current_shape(self):
        return self.orientations[self.rotation]

    def get_coordinates(self):
        return [(self.x+dx, self.y+dy) for dx,dy in self.get_current_shape()]

    def move(self, dx, dy, grid):
        if grid.is_valid_move(self, self.x+dx, self.y+dy):
            self.x += dx
            self.y += dy
            return True
        return False

    def rotate(self, grid):
        old_rot = self.rotation
        self.rotation = (self.rotation+1) % len(self.orientations)
        if not grid.is_valid_move(self, self.x, self.y):
            self.rotation = old_rot

    def draw(self, screen):
        for x, y in self.get_coordinates():
            pygame.draw.rect(screen, self.color, (x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
            pygame.draw.rect(screen, BLACK, (x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)  # Grid lines

class TetrominoGenerator:
    def __init__(self, grid_width):
        self.grid_width = grid_width
        self._bag = []
        self._refill()
    def _refill(self):
        self._bag = list(Tetromino.TETROMINO_SHAPES.keys())
        random.shuffle(self._bag)
    def next(self):
        if not self._bag:
            self._refill()
        t = self._bag.pop()
        start_x = self.grid_width//2 - 1
        return Tetromino(start_x, 0, t)


class Game:
    def __init__(self, width=GRID_WIDTH, height=GRID_HEIGHT):
        self.grid = Grid(width, height)
        self.generator = TetrominoGenerator(width)
        self.current = self.generator.next()
        self.score = 0
        self.drop_speed = 30 # frames
        self.drop_counter = 0

    def update(self):
        """Drop the current tetromino by 1. If it lands, lock it, clear, gravity, spawn next."""
        self.drop_counter += 1
        if self.drop_counter >= self.drop_speed:
            self.drop_counter = 0
            if self.current.move(0, 1, self.grid):
                return  # still falling
            # lock when it cannot move down
            self.grid.lock_shape(self.current)
            # Tetris line clear
            lines = self.grid.clear_full_rows()
            self.score += lines * 100
            # Bejeweled matches + gravity, allow chain reactions
            while True:
                cleared = self.grid.clear_matches()
                if cleared == 0:
                    break
                self.score += cleared * 10
                self.grid.apply_gravity()
            # spawn next
            self.current = self.generator.next()
            # if new piece collides immediately, game over
            if not self.grid.is_valid_move(self.current, self.current.x, self.current.y):
                raise Exception("Game Over")

    def handle_input(self, event):
        if event.type == pygame.KEYDOWN:
            if event.key == pygame.K_LEFT:
                self.current.move(-1, 0, self.grid)
            elif event.key == pygame.K_RIGHT:
                self.current.move(1, 0, self.grid)
            elif event.key == pygame.K_DOWN:
                self.current.move(0, 1, self.grid)
            elif event.key == pygame.K_UP:
                self.current.rotate(self.grid)

    def draw(self, screen):
        self.grid.draw(screen)
        self.current.draw(screen)
        font = pygame.font.Font(None, 36)
        text = font.render(f"Score: {self.score}", True, WHITE)
        screen.blit(text, (10, 10))

# Game loop
if __name__ == '__main__':
    game = Game()
    running = True

    while running:
        screen.fill(BLACK)
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            game.handle_input(event)

        try:
            game.update()
        except Exception as e:
            print(e, "Score:", game.score)
            running = False

        game.draw(screen)
        pygame.display.flip()
        clock.tick(FPS)

    pygame.quit()
